/**
 * Reverte a preparação do EAS: restaura @driver-profit/shared para "*" e remove .eas-shared
 */
const fs = require('fs');
const path = require('path');

const mobileRoot = path.resolve(__dirname, '..');
const targetDir = path.join(mobileRoot, '.eas-shared');
const pkgPath = path.join(mobileRoot, 'package.json');

const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf8'));
pkg.dependencies['@driver-profit/shared'] = '*';
fs.writeFileSync(pkgPath, JSON.stringify(pkg, null, 2) + '\n');

if (fs.existsSync(targetDir)) {
  fs.rmSync(targetDir, { recursive: true });
  console.log('Removido .eas-shared');
}
console.log('package.json restaurado para @driver-profit/shared: "*"');
